INSERT INTO usage_record (
    request_id, user_id, model_id, provider_key_id, input_tokens, output_tokens,
    total_tokens, usage_source, cost_amount
)
VALUES (
    #{requestId}, #{userId}, #{modelId}, #{providerKeyId}, #{inputTokens}, #{outputTokens},
    #{totalTokens}, #{usageSource}, #{costAmount}
)

mapper.select:
SELECT ur.user_id, u.username, DATE(ur.created_at) AS usage_date, COUNT(ur.id) AS call_count, COALESCE(SUM(ur.cost_amount), 0) AS total_cost FROM usage_record ur INNER JOIN user_account u ON u.id = ur.user_id
AND ur.user_id = #{userId}
AND ur.created_at >= #{startTime}
AND ur.created_at <= #{endTime}
GROUP BY ur.user_id, u.username, DATE(ur.created_at) ORDER BY usage_date DESC, ur.user_id ASC
